{
  "name": "TimeWarp Vision: 5s Future Predictor",
  "description": "An AI-powered camera app that captures the present and uses Gemini to generate a surreal, dramatic prediction of what happens 5 seconds into the future.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface PredictionData {
  originalImage: string;
  predictedImage: string;
  predictionText: string;
  timestamp: number;
}

export enum AppState {
  IDLE = 'IDLE',
  CAPTURING = 'CAPTURING',
  ANALYZING = 'ANALYZING',
  GENERATING = 'GENERATING',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Step 1: Analyze the current frame and describe a "5 seconds later" scenario.
 * We use Gemini 3 Flash for fast reasoning.
 */
export const predictFutureScenario = async (base64Image: string): Promise<string> => {
  const ai = getAI();

  const prompt = `
    Analyze this camera frame. 
    Predict a dramatic, visually interesting, and slightly surreal change that could occur 5 seconds from now.
    Focus on motion, transformation, or sudden events (e.g., something spills, a person changes expression drastically, a plant blooms rapidly, or objects start floating).

    Return the result in JSON format with a "prediction_prompt" field which will be used to generate a new image.
    The "prediction_prompt" should be a high-quality, descriptive prompt for an image generator, including artistic style (e.g. cinematic, hyper-realistic).
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          prediction_prompt: { type: Type.STRING },
          scenario_description: { type: Type.STRING, description: "A short text in Japanese explaining what happened." }
        },
        required: ["prediction_prompt", "scenario_description"]
      }
    }
  });

  return response.text || "";
};

/**
 * Step 2: Generate the predicted future image based on the scenario.
 * We use gemini-2.5-flash-image for editing/generating.
 */
export const generateFutureImage = async (originalBase64: string, predictionPrompt: string): Promise<string> => {
  const ai = getAI();

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: originalBase64.split(',')[1], mimeType: 'image/jpeg' } },
        { text: `Modify this scene to show the following scenario in 5 seconds: ${predictionPrompt}. Ensure the composition remains somewhat consistent but the change is clearly visible.` }
      ]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

import React, { useRef, useEffect, useCallback } from 'react';

interface CameraPreviewProps {
  onCapture: (base64: string) => void;
  isProcessing: boolean;
}

const CameraPreview: React.FC<CameraPreviewProps> = ({ onCapture, isProcessing }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const startCamera = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    };

    startCamera();

    return () => {
      if (videoRef.current && videoRef.current.srcObject) {
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const captureFrame = useCallback(() => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        onCapture(dataUrl);
      }
    }
  }, [onCapture]);

  return (
    <div className="relative group overflow-hidden rounded-2xl border-4 border-slate-700 bg-black aspect-video shadow-2xl">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className="w-full h-full object-cover grayscale-[0.3] group-hover:grayscale-0 transition-all duration-500"
      />
      <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none" />

      <div className="absolute top-4 left-4 flex items-center space-x-2">
        <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse" />
        <span className="text-xs font-orbitron text-white tracking-widest uppercase">Live Present</span>
      </div>

      {!isProcessing && (
        <button
          onClick={captureFrame}
          className="absolute bottom-6 left-1/2 -translate-x-1/2 px-8 py-3 bg-cyan-500 hover:bg-cyan-400 text-slate-900 font-bold rounded-full transition-all transform hover:scale-105 active:scale-95 shadow-lg shadow-cyan-500/50 flex items-center space-x-2"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M4 5a2 2 0 00-2 2v8a2 2 0 002 2h12a2 2 0 002-2V7a2 2 0 00-2-2h-1.586a1 1 0 01-.707-.293l-1.121-1.121A2 2 0 0011.172 3H8.828a2 2 0 00-1.414.586L6.293 4.707A1 1 0 015.586 5H4zm6 9a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
          </svg>
          <span>5秒後を視る</span>
        </button>
      )}

      {isProcessing && (
        <div className="absolute inset-0 bg-black/40 flex flex-col items-center justify-center backdrop-blur-sm">
          <div className="relative w-20 h-20 mb-4">
            <div className="absolute inset-0 border-4 border-cyan-500/20 rounded-full" />
            <div className="absolute inset-0 border-4 border-cyan-500 border-t-transparent rounded-full animate-spin" />
          </div>
          <p className="text-cyan-400 font-orbitron animate-pulse">Predicting Future...</p>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default CameraPreview;

import React from 'react';
import { PredictionData } from '../types';

interface PredictionCardProps {
