            link.click();
          }}
          className="text-xs text-slate-400 hover:text-cyan-400 transition-colors flex items-center"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
          </svg>
          保存する
        </button>
      </div>
    </div>
  );
};

export default PredictionCard;

import React, { useState, useCallback } from 'react';
import CameraPreview from './components/CameraPreview';
import PredictionCard from './components/PredictionCard';
import { AppState, PredictionData } from './types';
import { predictFutureScenario, generateFutureImage } from './services/geminiService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [lastPrediction, setLastPrediction] = useState<PredictionData | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleCapture = useCallback(async (base64: string) => {
    setAppState(AppState.ANALYZING);
    setError(null);

    try {
      // Step 1: Analyze frame with Gemini 3 Flash
      const analysisJson = await predictFutureScenario(base64);
      let parsed;
      try {
        parsed = JSON.parse(analysisJson);
      } catch (e) {
        console.error("Failed to parse AI response:", analysisJson);
        throw new Error("AIの応答を解析できませんでした。もう一度お試しください。");
      }

      setAppState(AppState.GENERATING);

      // Step 2: Generate image with Gemini 2.5 Flash Image
      const predictedImage = await generateFutureImage(base64, parsed.prediction_prompt);

      setLastPrediction({
        originalImage: base64,
        predictedImage,
        predictionText: parsed.scenario_description,
        timestamp: Date.now()
      });

      setAppState(AppState.IDLE);
    } catch (err: any) {
      console.error("Prediction error:", err);
      setError(err.message || "予期せぬエラーが発生しました。");
      setAppState(AppState.ERROR);
    }
  }, []);

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-8 space-y-8 bg-slate-950 text-slate-100">
      {/* Header */}
      <header className="w-full max-w-6xl flex flex-col md:flex-row justify-between items-center border-b border-slate-800 pb-6">
        <div className="mb-4 md:mb-0">
          <h1 className="text-3xl md:text-4xl font-orbitron font-bold tracking-tighter text-cyan-400">
            TIMEWARP<span className="text-fuchsia-500">.VISION</span>
          </h1>
          <p className="text-slate-400 text-sm mt-1 font-medium italic">
            "5 Seconds Later" AI Projection System
          </p>
        </div>

        <div className="flex items-center space-x-4">
          <div className={`px-4 py-1.5 rounded-full border text-xs font-orbitron tracking-widest uppercase transition-all duration-500 ${
            appState === AppState.IDLE ? 'border-slate-700 text-slate-500' :
            appState === AppState.ANALYZING ? 'border-yellow-500 text-yellow-500 animate-pulse' :
            appState === AppState.GENERATING ? 'border-fuchsia-500 text-fuchsia-500 animate-pulse' :
            'border-red-500 text-red-500'
          }`}>
            Status: {appState}
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        {/* Left: Live Input */}
        <section className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-orbitron tracking-tight flex items-center">
              <span className="w-2 h-2 bg-cyan-400 rounded-full mr-2 shadow-lg shadow-cyan-500" />
              Real-time Capture
            </h2>
          </div>
          <CameraPreview 
            onCapture={handleCapture} 
            isProcessing={appState === AppState.ANALYZING || appState === AppState.GENERATING} 
          />
          <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800 text-slate-400 text-xs leading-relaxed">
            <p className="font-bold text-slate-300 mb-1">💡 ヒント:</p>
            動きのある対象（手、飲み物、ペット、誰かの表情）に向けると、よりダイナミックな未来が生成されやすくなります。
          </div>
        </section>

        {/* Right: AI Prediction */}
        <section className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-orbitron tracking-tight flex items-center">
              <span className="w-2 h-2 bg-fuchsia-500 rounded-full mr-2 shadow-lg shadow-fuchsia-500" />
              Future Projection
            </h2>
          </div>
          <PredictionCard data={lastPrediction} />

          {error && (
            <div className="p-4 bg-red-900/20 border border-red-500/50 rounded-xl text-red-400 text-sm animate-bounce">
              <p className="flex items-center">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
                {error}
              </p>
            </div>
          )}
        </section>
      </main>

      {/* Footer Info */}
      <footer className="w-full max-w-6xl pt-12 pb-8 text-center text-slate-600 text-[10px] font-orbitron tracking-[0.2em] uppercase">
        Powered by Gemini Multi-Modal Intelligence Engine &bull; Experimental Future Projection V1.0
      </footer>
    </div>
  );
};

export default App;

export interface Target {
  x: number;
  y: number;
}

export interface PredictionData {
  originalImage: string;
  predictedImage: string;
  predictionText: string;
  timestamp: number;
}

export enum AppState {
  IDLE = 'IDLE',
  CAPTURING = 'CAPTURING',
  ANALYZING = 'ANALYZING',
  GENERATING = 'GENERATING',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Target } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Step 1: Analyze the current frame and describe a "5 seconds later" scenario.
 * We use Gemini 3 Flash for fast reasoning.
 */
export const predictFutureScenario = async (base64Image: string, target: Target | null): Promise<string> => {
  const ai = getAI();

  const targetContext = target 
    ? `The user has specifically targeted an object located at relative coordinates (x: ${target.x.toFixed(2)}, y: ${target.y.toFixed(2)}), where (0,0) is top-left and (1,1) is bottom-right of the image. 
       Focus your prediction specifically on the object or person at this location.`
    : "No specific target was selected. Predict a general dramatic change for the most prominent object in the scene.";

  const prompt = `
    Analyze this camera frame. 
    ${targetContext}

    Predict a dramatic, visually interesting, and slightly surreal change that could occur 5 seconds from now.
    Focus on motion, transformation, or sudden events related to the target area (e.g., something spills, a person changes expression drastically, a plant blooms rapidly, or objects start floating).

    Return the result in JSON format with a "prediction_prompt" field which will be used to generate a new image.
    The "prediction_prompt" should be a high-quality, descriptive prompt for an image generator, including artistic style (e.g. cinematic, hyper-realistic).
    Also include "scenario_description" in Japanese.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          prediction_prompt: { type: Type.STRING },
          scenario_description: { type: Type.STRING, description: "A short text in Japanese explaining what happened to the target." }
        },
        required: ["prediction_prompt", "scenario_description"]
      }
    }
  });

  return response.text || "";
};

/**
 * Step 2: Generate the predicted future image based on the scenario.
 * We use gemini-2.5-flash-image for editing/generating.
 */
export const generateFutureImage = async (originalBase64: string, predictionPrompt: string): Promise<string> => {
  const ai = getAI();

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: originalBase64.split(',')[1], mimeType: 'image/jpeg' } },
        { text: `Modify this scene to show the following scenario in 5 seconds: ${predictionPrompt}. Ensure the composition remains consistent but the targeted change is clearly visible.` }
      ]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Target } from '../types';

interface CameraPreviewProps {
  onCapture: (base64: string) => void;
  isProcessing: boolean;
  target: Target | null;
  onSetTarget: (target: Target | null) => void;
}

const CameraPreview: React.FC<CameraPreviewProps> = ({ onCapture, isProcessing, target, onSetTarget }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const startCamera = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    };

    startCamera();

    return () => {
      if (videoRef.current && videoRef.current.srcObject) {
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const handleVideoClick = (e: React.MouseEvent | React.TouchEvent) => {
    if (isProcessing) return;

    const container = containerRef.current;
    if (!container) return;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    const x = (clientX - rect.left) / rect.width;
    const y = (clientY - rect.top) / rect.height;

    onSetTarget({ x, y });
  };

  const captureFrame = useCallback(() => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        onCapture(dataUrl);
      }
    }
  }, [onCapture]);

  return (
    <div 
      ref={containerRef}
      onClick={handleVideoClick}
      className={`relative group overflow-hidden rounded-2xl border-4 ${target ? 'border-cyan-400' : 'border-slate-700'} bg-black aspect-video shadow-2xl cursor-crosshair transition-colors duration-300`}
    >
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className="w-full h-full object-cover grayscale-[0.3] group-hover:grayscale-0 transition-all duration-500"
      />
      <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none" />

      {/* Target Marker (Reticle) */}
      {target && (
        <div 
          className="absolute pointer-events-none transition-all duration-300 ease-out"
          style={{ 
            left: `${target.x * 100}%`, 
            top: `${target.y * 100}%`,
            transform: 'translate(-50%, -50%)'
          }}
        >
          <div className="relative w-12 h-12">
            <div className="absolute inset-0 border-2 border-cyan-400 rounded-full animate-ping opacity-75" />
            <div className="absolute inset-0 border-2 border-cyan-400 rounded-full" />
            <div className="absolute top-1/2 left-0 w-full h-0.5 bg-cyan-400 -translate-y-1/2" />
            <div className="absolute left-1/2 top-0 w-0.5 h-full bg-cyan-400 -translate-x-1/2" />
            <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-cyan-400 text-slate-900 text-[10px] px-1.5 py-0.5 font-bold rounded whitespace-nowrap">
              TARGET LOCKED
            </div>
          </div>
        </div>
      )}

      <div className="absolute top-4 left-4 flex items-center space-x-2">
        <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse" />
        <span className="text-xs font-orbitron text-white tracking-widest uppercase">Live Present</span>
      </div>

      <div className="absolute top-4 right-4 flex flex-col items-end space-y-2 pointer-events-none">
        <div className="bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-lg border border-white/10 text-[10px] font-orbitron text-cyan-400 uppercase tracking-widest">
          {target ? 'Target Selected' : 'Tap to Select Target'}
        </div>
      </div>

      {!isProcessing && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            captureFrame();
          }}
          className="absolute bottom-6 left-1/2 -translate-x-1/2 px-8 py-3 bg-cyan-500 hover:bg-cyan-400 text-slate-900 font-bold rounded-full transition-all transform hover:scale-105 active:scale-95 shadow-lg shadow-cyan-500/50 flex items-center space-x-2 z-10"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
