import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Target } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Step 1: Analyze the current frame and describe a "5 seconds later" scenario.
 * Focuses on realistic, logically sound predictions based on physical laws.
 */
export const predictFutureScenario = async (base64Image: string, target: Target | null): Promise<string> => {
  const ai = getAI();

  const targetContext = target 
    ? `The user has specifically targeted an object located at relative coordinates (x: ${target.x.toFixed(2)}, y: ${target.y.toFixed(2)}), where (0,0) is top-left and (1,1) is bottom-right of the image. 
       Focus your prediction specifically on the movement or state change of the object or person at this location.`
    : "No specific target was selected. Predict a realistic change for the most active or prominent element in the scene.";

  const prompt = `
    Analyze this camera frame. 
    ${targetContext}

    Predict a realistic and logically sound change that could occur exactly 5 seconds from now.
    CRITICAL: Avoid surreal, magical, or physically impossible events (such as objects floating, instant transformations, or supernatural elements).

    Focus on:
    - Plausible physical actions (e.g., a person finishing a movement, a door closing, a hand reaching for a cup).
    - Natural progression of motion (e.g., a rolling ball moving further, a person walking a few steps).
    - Subtle environmental shifts (e.g., lighting changes, steam rising, wind blowing hair).

    Return the result in JSON format with:
    1. "prediction_prompt": A high-quality, descriptive prompt for an image generator (gemini-2.5-flash-image) that depicts this realistic change. Maintain the current visual context and style.
    2. "scenario_description": A short, clear explanation in Japanese of what logically happened to the target or scene.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          prediction_prompt: { type: Type.STRING },
          scenario_description: { type: Type.STRING, description: "A short text in Japanese explaining the logical progression." }
        },
        required: ["prediction_prompt", "scenario_description"]
      }
    }
  });

  return response.text || "";
};

/**
 * Step 2: Generate the predicted future image based on the scenario.
 * We use gemini-2.5-flash-image for realistic editing.
 */
export const generateFutureImage = async (originalBase64: string, predictionPrompt: string): Promise<string> => {
  const ai = getAI();

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: originalBase64.split(',')[1], mimeType: 'image/jpeg' } },
        { text: `Modify this scene to show the following realistic 5-second progression: ${predictionPrompt}. Maintain identical lighting, shadows, and environment for maximum realism.` }
      ]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

