import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Target } from '../types';

interface CameraPreviewProps {
  onCapture: (base64: string) => void;
  isProcessing: boolean;
  target: Target | null;
  onSetTarget: (target: Target | null) => void;
}

const CameraPreview: React.FC<CameraPreviewProps> = ({ onCapture, isProcessing, target, onSetTarget }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const startCamera = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    };

    startCamera();

    return () => {
      if (videoRef.current && videoRef.current.srcObject) {
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const handleVideoClick = (e: React.MouseEvent | React.TouchEvent) => {
    if (isProcessing) return;

    const container = containerRef.current;
    if (!container) return;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    const x = (clientX - rect.left) / rect.width;
    const y = (clientY - rect.top) / rect.height;

    onSetTarget({ x, y });
  };

  const captureFrame = useCallback(() => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        onCapture(dataUrl);
      }
    }
  }, [onCapture]);

  return (
    <div 
      ref={containerRef}
      onClick={handleVideoClick}
      className={`relative group overflow-hidden rounded-2xl border-4 ${target ? 'border-cyan-400' : 'border-slate-700'} bg-black aspect-video shadow-2xl cursor-crosshair transition-colors duration-300`}
    >
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className="w-full h-full object-cover grayscale-[0.3] group-hover:grayscale-0 transition-all duration-500"
      />
      <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none" />

      {/* Target Marker (Reticle) */}
      {target && (
        <div 
          className="absolute pointer-events-none transition-all duration-300 ease-out"
          style={{ 
            left: `${target.x * 100}%`, 
            top: `${target.y * 100}%`,
            transform: 'translate(-50%, -50%)'
          }}
        >
          <div className="relative w-12 h-12">
            <div className="absolute inset-0 border-2 border-cyan-400 rounded-full animate-ping opacity-75" />
            <div className="absolute inset-0 border-2 border-cyan-400 rounded-full" />
            <div className="absolute top-1/2 left-0 w-full h-0.5 bg-cyan-400 -translate-y-1/2" />
            <div className="absolute left-1/2 top-0 w-0.5 h-full bg-cyan-400 -translate-x-1/2" />
            <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-cyan-400 text-slate-900 text-[10px] px-1.5 py-0.5 font-bold rounded whitespace-nowrap">
              TARGET LOCKED
            </div>
          </div>
        </div>
      )}

      <div className="absolute top-4 left-4 flex items-center space-x-2">
        <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse" />
        <span className="text-xs font-orbitron text-white tracking-widest uppercase">Live Present</span>
      </div>

      <div className="absolute top-4 right-4 flex flex-col items-end space-y-2 pointer-events-none">
        <div className="bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-lg border border-white/10 text-[10px] font-orbitron text-cyan-400 uppercase tracking-widest">
          {target ? 'Target Selected' : 'Tap to Select Target'}
        </div>
      </div>

      {!isProcessing && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            captureFrame();
          }}
          className="absolute bottom-6 left-1/2 -translate-x-1/2 px-8 py-3 bg-cyan-500 hover:bg-cyan-400 text-slate-900 font-bold rounded-full transition-all transform hover:scale-105 active:scale-95 shadow-lg shadow-cyan-500/50 flex items-center space-x-2 z-10"
