import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Target, PredictionData } from '../types';

interface CameraPreviewProps {
  onCapture: (base64: string) => void;
  isProcessing: boolean;
  target: Target | null;
  onSetTarget: (target: Target | null) => void;
  prediction: PredictionData | null;
}

const CameraPreview: React.FC<CameraPreviewProps> = ({ onCapture, isProcessing, target, onSetTarget, prediction }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [showFuture, setShowFuture] = useState(false);

  useEffect(() => {
    const startCamera = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1920 }, height: { ideal: 1080 } } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    };

    startCamera();

    return () => {
      if (videoRef.current && videoRef.current.srcObject) {
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  // Automatically flash the future when it arrives
  useEffect(() => {
    if (prediction) {
      setShowFuture(true);
      const timer = setTimeout(() => setShowFuture(false), 3000); // Flash for 3 seconds initially
      return () => clearTimeout(timer);
    }
  }, [prediction]);

  const handleVideoClick = (e: React.MouseEvent | React.TouchEvent) => {
    if (isProcessing) return;
    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }
    const x = (clientX - rect.left) / rect.width;
    const y = (clientY - rect.top) / rect.height;
    onSetTarget({ x, y });
  };

  const captureFrame = useCallback(() => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        onCapture(dataUrl);
      }
    }
  }, [onCapture]);

  return (
    <div 
      ref={containerRef}
      onClick={handleVideoClick}
      className={`relative w-full max-w-5xl mx-auto overflow-hidden rounded-3xl border-4 ${target ? 'border-cyan-500 shadow-[0_0_30px_rgba(6,182,212,0.3)]' : 'border-slate-800'} bg-black aspect-video transition-all duration-500 cursor-crosshair group`}
    >
      {/* 1. Base Video Feed */}
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className={`w-full h-full object-cover transition-all duration-700 ${showFuture ? 'opacity-20 scale-105 blur-sm' : 'opacity-100 scale-100'}`}
      />

      {/* 2. Future Projection Overlay (The "Flash") */}
      {prediction && (
        <div className={`absolute inset-0 transition-opacity duration-300 ${showFuture ? 'opacity-100 z-10' : 'opacity-0 -z-10 pointer-events-none'}`}>
          <img 
            src={prediction.predictedImage} 
            className="w-full h-full object-cover mix-blend-screen brightness-125"
            alt="Future Projection"
          />
          <div className="absolute inset-0 bg-fuchsia-500/10 animate-pulse mix-blend-overlay" />

          {/* Glitch Overlay Effect */}
          <div className="absolute inset-0 pointer-events-none opacity-30">
            <div className="w-full h-1 bg-white/20 absolute top-1/4 animate-bounce" />
            <div className="w-full h-1 bg-fuchsia-500/20 absolute top-2/3 animate-pulse" />
          </div>
        </div>
      )}

      {/* 3. HUD Layer */}
      <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between z-20">
        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-red-600 rounded-full animate-ping" />
              <span className="text-[10px] font-orbitron text-white tracking-[0.3em] uppercase opacity-70">Live Stream</span>
            </div>
            <div className="text-[20px] font-orbitron font-bold text-cyan-400 drop-shadow-md">
              {showFuture ? 'FUTURE_VISUAL_05M' : 'PRESENT_REAL_TIME'}
            </div>
          </div>

          <div className="text-right font-orbitron text-[10px] text-slate-500 tracking-widest leading-relaxed">
            SYSTEM_ID: TW-992<br />
            LOCATION: UNKNOWN<br />
            CHRONO: {new Date().toLocaleTimeString()}
          </div>
        </div>

        {/* Center Target Indicator */}
        {target && (
          <div 
            className="absolute transition-all duration-500"
            style={{ 
              left: `${target.x * 100}%`, 
              top: `${target.y * 100}%`,
              transform: 'translate(-50%, -50%)'
            }}
          >
            <div className="relative flex items-center justify-center">
              <div className="w-24 h-24 border border-cyan-500/30 rounded-full animate-[ping_3s_infinite]" />
              <div className="absolute w-16 h-16 border-2 border-cyan-400 rounded-lg animate-[spin_10s_linear_infinite]" />
              <div className="absolute w-2 h-2 bg-cyan-400 rounded-full shadow-[0_0_10px_cyan]" />

              {isProcessing && (
                <div className="absolute -bottom-16 w-48 text-center bg-cyan-500/10 backdrop-blur-md border border-cyan-500/40 py-1 rounded">
                  <span className="text-[10px] font-orbitron text-cyan-400 animate-pulse tracking-widest">ANALYZING_PHYSICS...</span>
                </div>
              )}
            </div>
          </div>
        )}

        <div className="flex justify-between items-end">
          <div className="bg-black/40 backdrop-blur-md p-3 rounded-lg border border-white/10 max-w-sm">
             <p className="text-[10px] font-orbitron text-slate-400 uppercase tracking-widest mb-1">Observation</p>
             <p className="text-sm font-medium text-white">
                {showFuture && prediction ? prediction.predictionText : (target ? 'TARGET LOCKED. READY FOR CHRONO-JUMP.' : 'TAP AN OBJECT TO TARGET.')}
             </p>
          </div>

          {prediction && (
            <button
              onMouseDown={() => setShowFuture(true)}
              onMouseUp={() => setShowFuture(false)}
              onTouchStart={() => setShowFuture(true)}
              onTouchEnd={() => setShowFuture(false)}
              className={`pointer-events-auto h-16 w-16 rounded-full border-2 border-fuchsia-500 flex items-center justify-center transition-all ${showFuture ? 'bg-fuchsia-500 scale-110 shadow-[0_0_30px_fuchsia]' : 'bg-black/40 hover:bg-fuchsia-500/20'}`}
            >
               <span className="text-[10px] font-orbitron font-bold text-white">FLASH</span>
            </button>
          )}
        </div>
      </div>

      {/* 4. Controls Overlay */}
      {!isProcessing && (
        <div className="absolute inset-x-0 bottom-8 flex justify-center pointer-events-none z-30">
          <button
            onClick={(e) => {
              e.stopPropagation();
              captureFrame();
            }}
            className="pointer-events-auto px-12 py-4 bg-white text-slate-950 font-orbitron font-bold rounded-full transition-all transform hover:scale-105 active:scale-95 shadow-2xl flex items-center space-x-3 group/btn"
          >
            <div className="w-3 h-3 bg-red-600 rounded-full group-hover/btn:scale-125 transition-transform" />
            <span>{target ? 'INITIATE_PROJECTION' : 'OPEN_CHRONO_EYE'}</span>
          </button>
        </div>
      )}

      {/* Loading Bar at top */}
      {isProcessing && (
        <div className="absolute top-0 left-0 w-full h-1 bg-slate-800 z-50">
          <div className="h-full bg-cyan-400 animate-[loading_2s_infinite]" style={{ width: '30%' }} />
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
      <style>{`
        @keyframes loading {
          0% { left: -30%; }
          100% { left: 100%; }
        }
      `}</style>
    </div>
  );
};

