export interface PredictionData {
  originalImage: string;
  items: PredictionItem[];
  timestamp: number;
}

export enum AppState {
  IDLE = 'IDLE',
  CAPTURING = 'CAPTURING',
  ANALYZING = 'ANALYZING',
  GENERATING = 'GENERATING',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Target } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface ScenarioResult {
  prediction_prompt: string;
  scenario_description: string;
  label: string;
}

/**
 * Step 1: Analyze frame and predict 3 distinct realistic 5-minute outcomes.
 */
export const predictFutureScenarios = async (base64Image: string, target: Target | null): Promise<ScenarioResult[]> => {
  const ai = getAI();

  const targetContext = target 
    ? `The user has specifically targeted an object at (x: ${target.x.toFixed(2)}, y: ${target.y.toFixed(2)}). 
       Focus on the movement, state change, or likely outcome for this specific object over the next 5 minutes.`
    : "Predict realistic changes for the most prominent elements in the scene over the next 5 minutes.";

  const prompt = `
    Analyze this camera frame. 
    ${targetContext}

    Predict 3 DISTINCT, realistic, and logically sound outcomes that could occur exactly 5 minutes from now.
    Avoid surreal or impossible events.

    Each outcome should be different (e.g., Scenario 1: Progressing a task, Scenario 2: Leaving the scene, Scenario 3: A slight environmental change).

    Return a JSON object with a "scenarios" array containing 3 items.
    Each item must have:
    1. "prediction_prompt": Detailed visual prompt for image generation.
    2. "scenario_description": Short Japanese text explaining the outcome.
    3. "label": A short unique label like "Timeline A", "Timeline B", "Timeline C".
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          scenarios: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                prediction_prompt: { type: Type.STRING },
                scenario_description: { type: Type.STRING },
                label: { type: Type.STRING }
              },
              required: ["prediction_prompt", "scenario_description", "label"]
            }
          }
        },
        required: ["scenarios"]
      }
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  return parsed.scenarios || [];
};

/**
 * Step 2: Generate a single future image based on a prompt.
 */
export const generateFutureImage = async (originalBase64: string, predictionPrompt: string): Promise<string> => {
  const ai = getAI();

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: originalBase64.split(',')[1], mimeType: 'image/jpeg' } },
        { text: `Modify this scene realistically for a 5-minute jump: ${predictionPrompt}. Keep composition consistent.` }
      ]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image generated");
};

import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Target, PredictionData } from '../types';

interface CameraPreviewProps {
  onCapture: (base64: string) => void;
  isProcessing: boolean;
  target: Target | null;
  onSetTarget: (target: Target | null) => void;
  prediction: PredictionData | null;
}

const CameraPreview: React.FC<CameraPreviewProps> = ({ onCapture, isProcessing, target, onSetTarget, prediction }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [showFuture, setShowFuture] = useState(false);
  const [selectedTimelineIndex, setSelectedTimelineIndex] = useState(0);

  useEffect(() => {
    const startCamera = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1920 }, height: { ideal: 1080 } } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    };
    startCamera();
    return () => {
      if (videoRef.current && videoRef.current.srcObject) {
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  useEffect(() => {
    if (prediction) {
      setShowFuture(true);
      const timer = setTimeout(() => setShowFuture(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [prediction]);

  const handleVideoClick = (e: React.MouseEvent | React.TouchEvent) => {
    if (isProcessing) return;
    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }
    onSetTarget({ x: (clientX - rect.left) / rect.width, y: (clientY - rect.top) / rect.height });
  };

  const captureFrame = useCallback(() => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        onCapture(canvas.toDataURL('image/jpeg', 0.8));
      }
    }
  }, [onCapture]);

  const currentTimeline = prediction?.items[selectedTimelineIndex];

  return (
    <div 
      ref={containerRef}
      onClick={handleVideoClick}
      className={`relative w-full max-w-5xl mx-auto overflow-hidden rounded-3xl border-4 ${target ? 'border-cyan-500 shadow-[0_0_40px_rgba(6,182,212,0.2)]' : 'border-slate-800'} bg-black aspect-video transition-all duration-500 cursor-crosshair group`}
    >
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className={`w-full h-full object-cover transition-all duration-700 ${showFuture ? 'opacity-20 scale-105 blur-md' : 'opacity-100 scale-100'}`}
      />

      {prediction && currentTimeline && (
        <div className={`absolute inset-0 transition-opacity duration-300 ${showFuture ? 'opacity-100 z-10' : 'opacity-0 -z-10 pointer-events-none'}`}>
          <img 
            src={currentTimeline.predictedImage} 
            className="w-full h-full object-cover mix-blend-screen brightness-125"
            alt="Future Timeline"
          />
          <div className="absolute inset-0 bg-fuchsia-500/10 animate-pulse mix-blend-overlay" />
        </div>
      )}

      {/* HUD Layer */}
      <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between z-20">
        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-red-600 rounded-full animate-ping" />
              <span className="text-[10px] font-orbitron text-white tracking-[0.3em] uppercase opacity-70">Live Stream</span>
            </div>
            <div className="text-[20px] font-orbitron font-bold text-cyan-400 drop-shadow-md">
              {showFuture ? `TIMELINE_${selectedTimelineIndex + 1}_05M` : 'PRESENT_REAL_TIME'}
            </div>
          </div>
          <div className="text-right font-orbitron text-[10px] text-slate-500 tracking-widest leading-relaxed">
            SCAN_RES: 1080p<br />
            PREDICTION_MOD: TRI-LINEAR<br />
            TIME: {new Date().toLocaleTimeString()}
          </div>
        </div>

        {target && (
          <div className="absolute transition-all duration-500" style={{ left: `${target.x * 100}%`, top: `${target.y * 100}%`, transform: 'translate(-50%, -50%)' }}>
            <div className="relative flex items-center justify-center">
              <div className="w-24 h-24 border border-cyan-500/30 rounded-full animate-[ping_3s_infinite]" />
              <div className="absolute w-2 h-2 bg-cyan-400 rounded-full shadow-[0_0_10px_cyan]" />
            </div>
          </div>
        )}

        <div className="flex justify-between items-end">
          <div className="bg-black/60 backdrop-blur-md p-4 rounded-xl border border-white/10 max-w-sm pointer-events-auto">
             <p className="text-[10px] font-orbitron text-slate-400 uppercase tracking-widest mb-1">Logic_Projection</p>
             <p className="text-sm font-medium text-white leading-relaxed">
                {showFuture && currentTimeline ? currentTimeline.predictionText : (target ? 'TARGET DETECTED. PREPARING 3 PARALLEL FUTURES.' : 'TAP TO SELECT PREDICTION TARGET.')}
             </p>

             {prediction && (
               <div className="mt-4 flex space-x-2">
                 {prediction.items.map((item, idx) => (
                   <button
                    key={idx}
                    onClick={(e) => { e.stopPropagation(); setSelectedTimelineIndex(idx); setShowFuture(true); }}
                    className={`flex-1 px-2 py-1.5 rounded text-[9px] font-orbitron border transition-all ${selectedTimelineIndex === idx ? 'bg-fuchsia-600 border-fuchsia-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                   >
                     {item.label || `T-${idx + 1}`}
                   </button>
                 ))}
               </div>
             )}
          </div>

          {prediction && (
            <button
              onMouseDown={() => setShowFuture(true)}
              onMouseUp={() => setShowFuture(false)}
              onTouchStart={() => setShowFuture(true)}
              onTouchEnd={() => setShowFuture(false)}
              className={`pointer-events-auto h-16 w-16 rounded-full border-2 border-fuchsia-500 flex items-center justify-center transition-all ${showFuture ? 'bg-fuchsia-500 scale-110 shadow-[0_0_30px_fuchsia]' : 'bg-black/40 hover:bg-fuchsia-500/20'}`}
            >
               <span className="text-[10px] font-orbitron font-bold text-white">FLASH</span>
            </button>
          )}
        </div>
      </div>

      {!isProcessing && (
        <div className="absolute inset-x-0 bottom-8 flex justify-center pointer-events-none z-30">
          <button
            onClick={(e) => { e.stopPropagation(); captureFrame(); }}
            className="pointer-events-auto px-10 py-3 bg-white text-slate-950 font-orbitron font-bold rounded-full transition-all transform hover:scale-105 active:scale-95 shadow-2xl flex items-center space-x-3 group/btn"
          >
            <div className="w-2.5 h-2.5 bg-red-600 rounded-full group-hover/btn:scale-125 transition-transform" />
            <span>{target ? 'GENERATE_TRIPLE_FUTURES' : 'INITIALIZE_SCANNER'}</span>
          </button>
        </div>
      )}

      {isProcessing && (
        <div className="absolute top-0 left-0 w-full h-1 bg-slate-800 z-50">
          <div className="h-full bg-cyan-400 animate-[loading_2s_infinite]" style={{ width: '40%' }} />
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
      <style>{`
        @keyframes loading { 0% { left: -40%; } 100% { left: 100%; } }
      `}</style>
    </div>
  );
};

export default CameraPreview;

import React, { useState, useCallback } from 'react';
